// TestBenchmarkRunnerEndToEnd verifies a full cell execution via shell adapter + harbor executor.
// Skipped when docker is unavailable.
func TestBenchmarkRunnerEndToEnd(t *testing.T) {
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	tmpDir := t.TempDir()
	outDir := filepath.Join(tmpDir, "results")

	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "2",
		"--out", outDir)
	cmd.Dir = benchDir

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("benchmark failed: %v\nstderr: %s", err, stderr.String())
	}

	cellsDir := filepath.Join(outDir, "cells")
	if _, err := os.Stat(cellsDir); err != nil {
		t.Fatalf("cells directory not created: %v", err)
	}

	foundCells := 0
	filepath.WalkDir(cellsDir, func(path string, d os.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.Name() == "report.json" {
			foundCells++
			reportPath := path
			data, err := os.ReadFile(reportPath)
			if err != nil {
				t.Errorf("failed to read report.json: %v", err)
				return nil
			}
			var report map[string]interface{}
			if err := json.Unmarshal(data, &report); err != nil {
				t.Errorf("report.json is not valid JSON: %v", err)
				return nil
			}
			if _, ok := report["cell_id"]; !ok {
				t.Errorf("report.json missing cell_id")
			}
			if _, ok := report["final_status"]; !ok {
				t.Errorf("report.json missing final_status")
			}
		}
		return nil
	})

	if foundCells == 0 {
		t.Fatalf("no cells executed (expected at least 1)")
	}

	sweepJSON := filepath.Join(outDir, "sweep.json")
	if _, err := os.Stat(sweepJSON); err != nil {
		t.Fatalf("sweep.json not created: %v", err)
	}
}

// TestBenchmarkRunnerResumeSkipsCompleted verifies that re-running with the same --out
// skips cells with terminal report.json unless --force-rerun is used.
func TestBenchmarkRunnerResumeSkipsCompleted(t *testing.T) {
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	outDir := filepath.Join(tmpDir, "results")

	cmd1 := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", outDir)
	cmd1.Dir = benchDir
	if err := cmd1.Run(); err != nil {
		t.Fatalf("first run failed: %v", err)
	}

	firstCells := make(map[string]bool)
	filepath.WalkDir(filepath.Join(outDir, "cells"), func(path string, d os.DirEntry, err error) error {
		if d.Name() == "report.json" {
			dir := filepath.Dir(path)
			firstCells[dir] = true
		}
		return nil
	})

	if len(firstCells) == 0 {
		t.Fatalf("first run produced no cells")
	}

	cmd2 := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
