// TestBenchmarkRunnerRetryInvalid verifies --retry-invalid reruns cells with
// non-empty invalid_class or orphan cell-state.json.
func TestBenchmarkRunnerRetryInvalid(t *testing.T) {
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	tmpDir := t.TempDir()
	outDir := filepath.Join(tmpDir, "results")

	cmd1 := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", outDir)
	cmd1.Dir = benchDir
	if err := cmd1.Run(); err != nil {
		t.Fatalf("initial run failed: %v", err)
	}

	var invalidCellDir string
	filepath.WalkDir(filepath.Join(outDir, "cells"), func(path string, d os.DirEntry, err error) error {
		if d.Name() == "report.json" && invalidCellDir == "" {
			data, err := os.ReadFile(path)
			if err == nil {
				var report map[string]interface{}
				if json.Unmarshal(data, &report) == nil {
					invalidCellDir = filepath.Dir(path)
				}
			}
		}
		return nil
	})

	if invalidCellDir == "" {
		t.Fatalf("no cells found to mark as invalid")
	}

	reportPath := filepath.Join(invalidCellDir, "report.json")
	reportData, err := os.ReadFile(reportPath)
	if err != nil {
		t.Fatalf("failed to read report.json: %v", err)
	}

	var report map[string]interface{}
	if err := json.Unmarshal(reportData, &report); err != nil {
		t.Fatalf("failed to parse report.json: %v", err)
	}

	report["invalid_class"] = "test_invalid"
	reportData, err = json.Marshal(report)
	if err != nil {
		t.Fatalf("failed to marshal report.json: %v", err)
	}

	if err := os.WriteFile(reportPath, reportData, 0644); err != nil {
		t.Fatalf("failed to write report.json: %v", err)
	}

	cmd2 := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--retry-invalid",
		"--out", outDir)
	cmd2.Dir = benchDir
	if err := cmd2.Run(); err != nil {
		t.Fatalf("retry-invalid run failed: %v", err)
	}

	retryReportPath := filepath.Join(invalidCellDir, "report.json")
	retryData, err := os.ReadFile(retryReportPath)
	if err != nil {
		t.Fatalf("failed to read retried report.json: %v", err)
	}

	var retryReport map[string]interface{}
	if err := json.Unmarshal(retryData, &retryReport); err != nil {
		t.Fatalf("failed to parse retried report.json: %v", err)
	}

	if supersededBy, ok := retryReport["superseded_by"]; !ok || supersededBy == "" {
		t.Errorf("retried cell should have superseded_by set, got: %v", retryReport)
	}
}

